# Minimal MCP server example: exposing an internal CRM API to Claude
# Requires: pip install mcp

from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp.types import Tool, TextContent
import httpx, json

server = Server("crm-connector")

@server.list_tools()
async def list_tools():
    return [
        Tool(
            name="get_customer",
            description="Retrieve a customer record by email address",
            inputSchema={
                "type": "object",
                "properties": {
                    "email": {"type": "string", "description": "Customer email address"}
                },
                "required": ["email"]
            }
        ),
        Tool(
            name="list_open_tickets",
            description="List open support tickets for a customer",
            inputSchema={
                "type": "object",
                "properties": {
                    "customer_id": {"type": "string"}
                },
                "required": ["customer_id"]
            }
        )
    ]

@server.call_tool()
async def call_tool(name: str, arguments: dict):
    headers = {"Authorization": f"Bearer {CRM_API_KEY}"}

    if name == "get_customer":
        async with httpx.AsyncClient() as client:
            r = await client.get(
                f"{CRM_BASE_URL}/customers",
                params={"email": arguments["email"]},
                headers=headers
            )
            r.raise_for_status()
            return [TextContent(type="text", text=json.dumps(r.json(), indent=2))]

    if name == "list_open_tickets":
        async with httpx.AsyncClient() as client:
            r = await client.get(
                f"{CRM_BASE_URL}/tickets",
                params={"customer_id": arguments["customer_id"], "status": "open"},
                headers=headers
            )
            r.raise_for_status()
            return [TextContent(type="text", text=json.dumps(r.json(), indent=2))]

CRM_API_KEY = "..."
CRM_BASE_URL = "https://api.internal-crm.example.com"

if __name__ == "__main__":
    import asyncio
    asyncio.run(stdio_server(server))

# jira_mcp_server.py
import asyncio, json, httpx, os
from mcp.server import Server
from mcp.server.sse import sse_server
from mcp.types import Tool, TextContent

server = Server('jira-connector')
JIRA_BASE = os.environ['JIRA_BASE_URL']
AUTH = (os.environ['JIRA_EMAIL'], os.environ['JIRA_API_TOKEN'])

@server.list_tools()
async def list_tools():
    return [
        Tool(
            name='search_issues',
            description='Search Jira issues using JQL',
            inputSchema={
                'type': 'object',
                'properties': {
                    'jql': {'type': 'string'},
                    'max_results': {'type': 'integer', 'default': 20}
                },
                'required': ['jql']
            }
        ),
    ]

@server.call_tool()
async def call_tool(name: str, arguments: dict):
    async with httpx.AsyncClient(auth=AUTH) as client:
        if name == 'search_issues':
            r = await client.get(
                f'{JIRA_BASE}/rest/api/3/search',
                params={'jql': arguments['jql'],
                        'maxResults': arguments.get('max_results', 20),
                        'fields': 'summary,status,priority,assignee'}
            )
            r.raise_for_status()
            issues = r.json().get('issues', [])
            simplified = [
                {'key': i['key'],
                 'summary': i['fields']['summary'],
                 'status': i['fields']['status']['name'],
                 'priority': i['fields']['priority']['name']}
                for i in issues
            ]
            return [TextContent(type='text', text=json.dumps(simplified, indent=2))]

if __name__ == '__main__':
    asyncio.run(sse_server(server, host='0.0.0.0', port=8080))
